 58→/** Scrape resultaten ophalen, optioneel gefilterd op platform en gelimiteerd */
 59→export async function getHistory(opts: GetHistoryOptions = {}): Promise<ScrapeResult[]> {
 60→  const limit = Math.min(opts.limit ?? 50, 100);
 61→
 62→  const baseQuery = db.select().from(scrapeResults);
 63→  const filtered = opts.platform
 64→    ? baseQuery.where(eq(scrapeResults.platform, opts.platform))
 65→    : baseQuery;
 66→
 67→  return filtered.orderBy(desc(scrapeResults.runAt)).limit(limit);
 68→}
