 70→/** Bereken analytics per platform over alle scrape resultaten */
 71→export async function getAnalytics(): Promise<ScrapeAnalytics> {
 72→  const rows = await db
 73→    .select({
 74→      platform: scrapeResults.platform,
 75→      totalRuns: sql<number>`count(*)::int`,
 76→      successCount: sql<number>`count(*) filter (where ${scrapeResults.status} = 'success')::int`,
 77→      failedCount: sql<number>`count(*) filter (where ${scrapeResults.status} = 'failed')::int`,
 78→      totalJobsFound: sql<number>`coalesce(sum(${scrapeResults.jobsFound}), 0)::int`,
 79→      totalJobsNew: sql<number>`coalesce(sum(${scrapeResults.jobsNew}), 0)::int`,
 80→      totalDuplicates: sql<number>`coalesce(sum(${scrapeResults.duplicates}), 0)::int`,
 81→      avgDurationMs: sql<number>`coalesce(avg(${scrapeResults.durationMs}), 0)::int`,
 82→    })
 83→    .from(scrapeResults)
 84→    .groupBy(scrapeResults.platform);
 85→
 86→  const [uniqueJobsResult] = await db
 87→    .select({ count: sql<number>`count(*)::int` })
 88→    .from(jobs)
 89→    .where(sql`${jobs.deletedAt} is null`);
 90→
 91→  const totalUniqueJobs = uniqueJobsResult?.count ?? 0;
 92→
 93→  const byPlatform: PlatformStats[] = rows.map((r) => ({
 94→    ...r,
 95→    successRate: r.totalRuns > 0 ? Math.round((r.successCount / r.totalRuns) * 100) : 0,
 96→  }));
 97→
 98→  const totalRuns = byPlatform.reduce((s, p) => s + p.totalRuns, 0);
 99→  const totalSuccess = byPlatform.reduce((s, p) => s + p.successCount, 0);
100→
101→  return {
102→    totalRuns,
103→    totalJobsFound: byPlatform.reduce((s, p) => s + p.totalJobsFound, 0),
104→    totalJobsNew: byPlatform.reduce((s, p) => s + p.totalJobsNew, 0),
105→    totalDuplicates: byPlatform.reduce((s, p) => s + p.totalDuplicates, 0),
106→    totalUniqueJobs,
107→    overallSuccessRate: totalRuns > 0 ? Math.round((totalSuccess / totalRuns) * 100) : 0,
108→    avgDurationMs:
109→      totalRuns > 0
110→        ? Math.round(byPlatform.reduce((s, p) => s + p.avgDurationMs * p.totalRuns, 0) / totalRuns)
111→        : 0,
112→    byPlatform,
113→  };
114→}
