 32→function mapBasicListing(job) {
 33→  const loc = job.locationName ?? "";
 34→  const province = loc.includes(" - ") ? loc.split(" - ")[1]?.trim() : undefined;
 35→
 36→  return {
 37→    title: job.title ?? "",
 38→    company: job.client?.name ?? "",
 39→    location: loc || undefined,
 40→    province,
 41→    description: job.description ?? job.shortDescription ?? "",
 42→    externalId: job.referenceCode ?? String(job.id ?? ""),
 43→    externalUrl: \`https://supplier.striive.com/jobrequests/\${job.id ?? ""}\`,
 44→    rateMax: undefined,
 45→    startDate: job.startDate ?? undefined,
 46→    endDate: job.endDate ?? undefined,
 47→    applicationDeadline: job.closingDateOffer ?? undefined,
 48→    postedAt: job.publishedAt ?? undefined,
 49→    contractLabel: job.source ?? undefined,
 50→    positionsAvailable: 1,
