332→async function scrapeViaModal(username: string, password: string): Promise<RawScrapedListing[]> {
333→  const { ModalClient } = await import("modal");
334→  console.log("[striive] Starting Modal sandbox scrape...");
335→
336→  try {
337→    const modal = new ModalClient();
338→    const app = await modal.apps.fromName("motian-scraper", { createIfMissing: true });
339→
340→    const image = modal.images
341→      .fromRegistry("node:22-slim")
342→      .dockerfileCommands([
343→        "RUN apt-get update && apt-get install -y wget gnupg ca-certificates",
344→        "RUN cd /root && npm init -y && npm install playwright-core",
345→        "RUN npx --yes playwright install --with-deps chromium",
346→      ]);
347→
348→    const sandbox = await modal.sandboxes.create(app, image, {
349→      env: {
350→        STRIIVE_USERNAME: username,
351→        STRIIVE_PASSWORD: password,
352→      },
353→      timeoutMs: 10 * 60 * 1000,
354→      workdir: "/root",
355→    });
356→
357→    console.log("[striive] Modal sandbox created, executing scrape script...");
358→
359→    // Write the scraping script into the sandbox
360→    await sandbox.exec(
361→      ["bash", "-c", `cat > /root/scrape.js << 'SCRIPT_EOF'\n${MODAL_SCRAPE_SCRIPT}\nSCRIPT_EOF`],
362→      { timeoutMs: 10_000 },
363→    );
364→
365→    // Execute the script
366→    const proc = await sandbox.exec(["node", "/root/scrape.js"], {
367→      timeoutMs: 8 * 60 * 1000,
368→    });
369→
370→    const exitCode = await proc.wait();
371→    const stdout = await proc.stdout.readText();
372→    const stderr = await proc.stderr.readText();
373→
374→    await sandbox.terminate().catch(() => {});
375→
376→    if (exitCode !== 0) {
377→      const stderrSnippet = stderr ? stderr.substring(0, 500) : "(no stderr)";
378→      console.error(`[striive] Modal sandbox exited with code ${exitCode}`);
379→      if (stdout) console.error(`[striive] stdout: ${stdout.substring(0, 500)}`);
380→      if (stderr) console.error(`[striive] stderr: ${stderrSnippet}`);
381→      throw new Error(`Modal sandbox exited with code ${exitCode}: ${stderrSnippet}`);
382→    }
383→
384→    // Extract JSON results from the sentinel marker in stdout
385→    const marker = "__MODAL_RESULT__";
386→    const markerIdx = stdout.indexOf(marker);
387→    if (markerIdx === -1) {
388→      const stdoutSnippet = stdout.substring(0, 500);
389→      throw new Error(
390→        `Striive Modal: geen resultaat-marker in sandbox output. stdout: ${stdoutSnippet}`,
391→      );
392→    }
393→
394→    const results = JSON.parse(stdout.substring(markerIdx + marker.length));
395→    console.log(`[striive] Modal sandbox returned ${results.length} listings`);
396→    return results;
397→  } catch (err) {
398→    throw new Error(
399→      `Striive Modal scrape mislukt: ${err instanceof Error ? err.message : String(err)}`,
400→      { cause: err },
401→    );
402→  }
403→}
